// Input: mode ('pre_a1' | 'post_a1'), detected_domain (if post_a1)
// + raw GitHub API responses from HTTP Request nodes
const mode           = $input.first().json.mode || 'pre_a1';
const detected_domain = $input.first().json.detected_domain || null;
const common_raw     = $('Load Common Glossary').first().json;
const domain_raw     = mode === 'post_a1' ? $('Load Domain TM').first().json : null;

// Decode common glossary (base64 content from GitHub API)
let common_glossary = [];
try {
  const decoded = Buffer.from(common_raw.content, 'base64').toString('utf-8');
  const parsed  = JSON.parse(decoded);
  common_glossary = parsed.terms || [];
} catch(e) {
  common_glossary = [];
}

// Decode domain TM CSV (if post_a1)
let domain_tm = [];
if (domain_raw && domain_raw.content) {
  try {
    const csv = Buffer.from(domain_raw.content, 'base64').toString('utf-8');
    const lines = csv.trim().split('\n');
    if (lines.length > 1) {
      const headers = lines[0].split(',');
      for (let i = 1; i < lines.length; i++) {
        const vals = lines[i].split(',');
        if (vals[0]) {  // source_term not empty
          const entry = {};
          headers.forEach((h,idx) => entry[h.trim()] = (vals[idx]||'').trim());
          domain_tm.push(entry);
        }
      }
    }
  } catch(e) {
    domain_tm = [];
  }
}

// Separate validated vs agent-generated in domain TM
const domain_validated  = domain_tm.filter(t => t.validated === 'true');
const domain_unvalidated = domain_tm.filter(t => t.validated !== 'true');

return [{ json: {
  mode,
  detected_domain,
  common_glossary,           // 79 terms — absolute authority
  domain_validated_tm: domain_validated,    // human-reviewed — impose without re-decision
  domain_unvalidated_tm: domain_unvalidated, // agent-generated — A2 must confirm
  total_common: common_glossary.length,
  total_domain: domain_tm.length,
  glossary_loaded_at: new Date().toISOString()
}}];

